scwin.f_branchAggrDeptCdPopUp = async function () {
  await udc_branchAggrDept.cfCommonPopUp(async function (rtnList) {
    if (!$c.gus.cfIsNull($p, rtnList)) {
      if (rtnList[8] != 1) {
        //집계부서가 아니면 리턴
        await $c.gus.alert($p, "지사/집계부서는 집계부서인 경우만 선택이 가능합니다.");
        ed_branchAggrDeptCd.setValue("");
        ed_branchAggrDeptNm.setValue("");
        return;
      } else {
        ed_branchAggrDeptCd.setValue(rtnList[0]);
        ed_branchAggrDeptNm.setValue(rtnList[1]);
      }
    } else {
      ed_branchAggrDeptCd.setValue("");
      ed_branchAggrDeptNm.setValue("");
    }
  }, ed_branchAggrDeptCd.getValue(), "", "T", null, null, null, null, null, null, null, null, null);
};

