scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
  await udc_company.cfCommonPopUp(function (rtnList) {
    if ($c.gus.cfIsNull($p, rtnList)) {
      if (rtnList[0] == "N/A") return;
      ed_coCd.setValue(rtnList[0]); // 코드
      ed_coNm.setValue(rtnList[5]); // 회사명 
      ed_coCd.options.hidVal = rtnList[0]; // 히든값 
      lc_coClsCd.getValue(rtnList[1]); // 회사구분

      if (rtnList[1] == '0') {
        chb_virtureDeptYn.setValue("N");
        //chb_virtureDeptYn.checked = false;
      } else if (rtnList[1] > '0') {
        // 자회사인 경우에만 
        chb_virtureDeptYn.setValue("Y");
        //chb_virtureDeptYn.checked = true;
      }
    } else {
      ed_coCd.setValue("");
      ed_coNm.setValue("");
      ed_coCd.options.hidVal = "";
      chb_virtureDeptYn.setValue("N");
      //chb_virtureDeptYn.checked = false;
    }
  }, ed_coCd.getValue(), ed_coNm.getValue(), pWinCloseTF, null, null, null, null, null, null, null, null, null);
  // SET	 
};
